simple.afterForm:
[
    {
        "type": "divider"
    },
    {
        "type": "panel",
        "title": "查询结果",
        "visibleOn": "this.symbol != null",
        "body": [
            {
                "type": "alert",
                "level": "info",
                "body": "当前类型: ${symbol.qualifiedName | default:'-'} (${symbol.kind | default:'-'})"
            },
            {
                "type": "panel",
                "title": "父类型 (Super Types)",
                "visibleOn": "this.superTypes != null && this.superTypes.length > 0",
                "collapsable": true,
                "body": {
                    "type": "json",
                    "source": "${superTypes}",
                    "levelExpand": 10
                }
            },
            {
                "type": "panel",
                "title": "子类型 (Sub Types)",
                "visibleOn": "this.subTypes != null && this.subTypes.length > 0",
                "collapsable": true,
                "body": {
                    "type": "json",
                    "source": "${subTypes}",
                    "levelExpand": 10
                }
            }
        ]
    }
]
